import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getDashboardStats, getMyTasks, getTasks } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { isPast } from 'date-fns';

export default function Dashboard() {
  const { user, isAdmin } = useAuth();
  const [stats, setStats] = useState(null);
  const [recentTasks, setRecentTasks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [statsRes, tasksRes] = await Promise.all([
          getDashboardStats(),
          isAdmin ? getTasks() : getMyTasks()
        ]);
        setStats(statsRes.data.stats);
        setRecentTasks((tasksRes.data.tasks || []).slice(0, 5));
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [isAdmin]);

  if (loading) return <div style={{textAlign:'center',padding:'60px',fontSize:'18px',color:'#fff'}}>Loading...</div>;

  return (
    <div style={{minHeight:'100vh',padding:'30px',background:'linear-gradient(135deg,#0f172a,#022c22)'}}>

      {/* HEADER */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'30px'}}>
        <div>
          <h1 style={{fontSize:'34px',fontWeight:'800',color:'#4ade80'}}>Dashboard</h1>
          <p style={{fontSize:'15px',color:'#bbf7d0'}}>Welcome back, {user?.name} 👋</p>
        </div>

        {isAdmin && (
          <Link to="/projects" style={{padding:'10px 18px',background:'#22c55e',color:'#022c22',borderRadius:'8px',textDecoration:'none',fontWeight:'600'}}>+ New Project</Link>
        )}
      </div>

      {/* STATS */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:'20px',marginBottom:'30px'}}>
        {[
          { label: 'Total Tasks', value: stats?.total || 0 },
          { label: 'In Progress', value: stats?.inProgress || 0 },
          { label: 'Completed', value: stats?.completed || 0 },
          { label: 'Overdue', value: stats?.overdue || 0 }
        ].map((item, i) => (
          <div key={i} style={{background:'rgba(255,255,255,0.06)',padding:'25px',borderRadius:'14px',border:'1px solid rgba(255,255,255,0.1)',backdropFilter:'blur(10px)'}}>
            <div style={{fontSize:'26px',fontWeight:'700',color:'#4ade80'}}>{item.value}</div>
            <div style={{fontSize:'14px',marginTop:'5px',color:'#bbf7d0'}}>{item.label}</div>
          </div>
        ))}
      </div>

      {/* PROGRESS */}
      {stats?.total > 0 && (
        <div style={{background:'rgba(255,255,255,0.06)',padding:'20px',borderRadius:'14px',marginBottom:'25px',border:'1px solid rgba(255,255,255,0.1)'}}>
          <h3 style={{fontSize:'16px',marginBottom:'12px',color:'#fff'}}>Overall Progress</h3>

          <div style={{display:'flex',height:'10px',borderRadius:'6px',overflow:'hidden'}}>
            <div style={{flex:stats.todo,background:'#374151'}}></div>
            <div style={{flex:stats.inProgress,background:'#22c55e'}}></div>
            <div style={{flex:stats.review,background:'#eab308'}}></div>
            <div style={{flex:stats.completed,background:'#4ade80'}}></div>
          </div>
        </div>
      )}

      {/* TASKS */}
      <div style={{background:'rgba(255,255,255,0.06)',padding:'20px',borderRadius:'14px',border:'1px solid rgba(255,255,255,0.1)'}}>

        <div style={{display:'flex',justifyContent:'space-between',marginBottom:'15px'}}>
          <h3 style={{fontSize:'18px',color:'#fff'}}>Recent Tasks</h3>
          <Link to={isAdmin ? '/tasks' : '/my-tasks'} style={{fontSize:'14px',color:'#4ade80'}}>View all →</Link>
        </div>

        {recentTasks.length === 0 ? (
          <p style={{textAlign:'center',color:'#9ca3af'}}>No tasks yet</p>
        ) : (
          <div style={{display:'flex',flexDirection:'column',gap:'12px'}}>
            {recentTasks.map(task => (
              <div key={task._id} style={{padding:'14px',border:'1px solid rgba(255,255,255,0.1)',borderRadius:'10px',display:'flex',justifyContent:'space-between',alignItems:'center',background:'rgba(0,0,0,0.2)'}}>

                <div>
                  <div style={{fontSize:'15px',fontWeight:'600',color:'#fff'}}>{task.title}</div>
                  <div style={{fontSize:'12px',color:'#9ca3af',marginTop:'3px'}}>
                    {task.project?.name} {task.assignedTo && `• ${task.assignedTo.name}`}
                  </div>
                </div>

                <div style={{display:'flex',gap:'10px',alignItems:'center'}}>
                  {task.deadline && isPast(new Date(task.deadline)) && task.status !== 'completed' && (
                    <span style={{fontSize:'12px',color:'#f87171'}}>Overdue</span>
                  )}
                  <span style={{fontSize:'12px',padding:'4px 10px',background:'#1f2937',borderRadius:'6px',color:'#e5e7eb'}}>
                    {task.status}
                  </span>
                </div>

              </div>
            ))}
          </div>
        )}

      </div>

    </div>
  );
}
